#include<bits/stdc++.h>
using namespace std;
struct node{
	int a,b;
}c[1010];
int cmp(node e,node d)
{
	return e.b<d.b;
}
int n;
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
    	scanf("%d",&c[i].a);
	}
    for(int i=1;i<n;i++)
    {
    	c[i].b=abs(c[i+1].a-c[i].a);
	}
    sort(c+1,c+n,cmp);
	for(int i=1;i<n;i++)
	{
		if(c[i].b!=i)
		{
			printf("Not jolly");
			return 0;
		}
	}
	printf("Jolly");
	return 0;
}
